import React, { useState, useEffect } from 'react';
import { saveTagConfig } from '../api';
import { MqttTagConfig } from '../types';

interface Props {
    config: MqttTagConfig | null;
    onConfigSaved: (config: MqttTagConfig) => void;
}

const TagSelection: React.FC<Props> = ({ config, onConfigSaved }) => {
    const [formData, setFormData] = useState<MqttTagConfig>({
        name: 'Default Tag Publishing',
        enabled: false,
        tagProviders: ['default'],
        tagFolders: [],
        topicOverrides: {},
        payloadTemplate: '',
        includeMetadata: true,
        valueDeadband: 0.1,
        publishOnQualityChange: true
    });

    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [newProvider, setNewProvider] = useState('');
    const [newFolder, setNewFolder] = useState('');

    useEffect(() => {
        if (config) {
            setFormData(config);
        }
    }, [config]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;

        if (type === 'checkbox') {
            setFormData(prev => ({
                ...prev,
                [name]: (e.target as HTMLInputElement).checked
            }));
        } else if (type === 'number') {
            setFormData(prev => ({
                ...prev,
                [name]: parseFloat(value)
            }));
        } else {
            setFormData(prev => ({
                ...prev,
                [name]: value
            }));
        }
    };

    const addProvider = () => {
        if (newProvider && !formData.tagProviders.includes(newProvider)) {
            setFormData(prev => ({
                ...prev,
                tagProviders: [...prev.tagProviders, newProvider]
            }));
            setNewProvider('');
        }
    };

    const removeProvider = (provider: string) => {
        setFormData(prev => ({
            ...prev,
            tagProviders: prev.tagProviders.filter(p => p !== provider)
        }));
    };

    const addFolder = () => {
        if (newFolder && !formData.tagFolders.includes(newFolder)) {
            setFormData(prev => ({
                ...prev,
                tagFolders: [...prev.tagFolders, newFolder]
            }));
            setNewFolder('');
        }
    };

    const removeFolder = (folder: string) => {
        setFormData(prev => ({
            ...prev,
            tagFolders: prev.tagFolders.filter(f => f !== folder)
        }));
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setMessage(null);

        try {
            const response = await saveTagConfig(formData);

            if (response.success && response.data) {
                setMessage({ type: 'success', text: 'Tag configuration saved successfully' });
                onConfigSaved(response.data);
            } else {
                throw new Error(response.error || 'Failed to save configuration');
            }
        } catch (error) {
            setMessage({
                type: 'error',
                text: error instanceof Error ? error.message : 'Failed to save configuration'
            });
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="tag-selection">
            <form onSubmit={handleSave}>
                <div className="form-section">
                    <h2>Tag Selection</h2>

                    <div className="form-group">
                        <label>Tag Providers</label>
                        <div className="list-input">
                            <input
                                type="text"
                                value={newProvider}
                                onChange={(e) => setNewProvider(e.target.value)}
                                placeholder="Enter provider name (e.g., default)"
                                onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addProvider())}
                            />
                            <button type="button" onClick={addProvider} className="btn-add">
                                Add Provider
                            </button>
                        </div>
                        <ul className="item-list">
                            {formData.tagProviders.map(provider => (
                                <li key={provider}>
                                    {provider}
                                    <button
                                        type="button"
                                        onClick={() => removeProvider(provider)}
                                        className="btn-remove"
                                    >
                                        Remove
                                    </button>
                                </li>
                            ))}
                        </ul>
                        <small>Specify which tag providers to monitor for changes</small>
                    </div>

                    <div className="form-group">
                        <label>Tag Folders</label>
                        <div className="list-input">
                            <input
                                type="text"
                                value={newFolder}
                                onChange={(e) => setNewFolder(e.target.value)}
                                placeholder="Enter folder path (e.g., [default]Folder/Subfolder)"
                                onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addFolder())}
                            />
                            <button type="button" onClick={addFolder} className="btn-add">
                                Add Folder
                            </button>
                        </div>
                        <ul className="item-list">
                            {formData.tagFolders.map(folder => (
                                <li key={folder}>
                                    {folder}
                                    <button
                                        type="button"
                                        onClick={() => removeFolder(folder)}
                                        className="btn-remove"
                                    >
                                        Remove
                                    </button>
                                </li>
                            ))}
                        </ul>
                        <small>Specify folders to monitor. Leave empty to monitor all tags in selected providers.</small>
                    </div>
                </div>

                <div className="form-section">
                    <h2>Publishing Settings</h2>

                    <div className="form-group">
                        <label htmlFor="valueDeadband">Value Deadband</label>
                        <input
                            type="number"
                            id="valueDeadband"
                            name="valueDeadband"
                            value={formData.valueDeadband}
                            onChange={handleChange}
                            min={0}
                            step={0.01}
                        />
                        <small>Minimum change required to publish (prevents noise from small fluctuations)</small>
                    </div>

                    <div className="form-group">
                        <label htmlFor="payloadTemplate">Payload Template (optional)</label>
                        <textarea
                            id="payloadTemplate"
                            name="payloadTemplate"
                            value={formData.payloadTemplate || ''}
                            onChange={handleChange}
                            placeholder="Leave empty for default JSON format"
                            rows={4}
                        />
                        <small>Custom JSON template for message payload (advanced users only)</small>
                    </div>

                    <div className="form-group checkbox">
                        <label>
                            <input
                                type="checkbox"
                                name="includeMetadata"
                                checked={formData.includeMetadata}
                                onChange={handleChange}
                            />
                            Include metadata (timestamp, quality, datatype)
                        </label>
                    </div>

                    <div className="form-group checkbox">
                        <label>
                            <input
                                type="checkbox"
                                name="publishOnQualityChange"
                                checked={formData.publishOnQualityChange}
                                onChange={handleChange}
                            />
                            Publish when tag quality changes
                        </label>
                    </div>
                </div>

                <div className="form-section">
                    <h2>Module Settings</h2>

                    <div className="form-group checkbox">
                        <label>
                            <input
                                type="checkbox"
                                name="enabled"
                                checked={formData.enabled}
                                onChange={handleChange}
                            />
                            <strong>Enable tag publishing</strong>
                        </label>
                        <small>Tag publishing must be enabled to monitor and publish tag changes</small>
                    </div>
                </div>

                {message && (
                    <div className={`message ${message.type}`}>
                        {message.text}
                    </div>
                )}

                <div className="form-actions">
                    <button
                        type="submit"
                        disabled={saving}
                        className="btn-primary"
                    >
                        {saving ? 'Saving...' : 'Save Configuration'}
                    </button>
                </div>
            </form>
        </div>
    );
};

export default TagSelection;
